>header button{width:48px;height:48px;border:1px solid #dcd2c2;border-radius:999px;background:#fff;font-size:1.5rem}.detail{display:grid;gap:1rem}.detail>section{padding:1rem;border:1px solid #dcd2c2;border-radius:1rem;background:#fffcf7}.history{display:grid;gap:.2rem;padding:.75rem 0;border-top:1px solid #eee5d8}.history p{margin:.15rem 0;color:#67675f}
